xpath.script:

(function() {
    // Función para obtener el ID del proveedor seleccionado
    function getSelectedPaymentProviderId() {
        var selectedInput = document.querySelector('input[name="o_payment_radio"]:checked');
        if (!selectedInput) return null;
        // Intentar diferentes atributos
        var providerId = selectedInput.getAttribute('data-payment-option-id') ||
                         selectedInput.getAttribute('data-provider-id') ||
                         selectedInput.getAttribute('data-id') ||
                         selectedInput.value;
        console.log('Selected radio:', selectedInput);
        console.log('All attributes:', Array.from(selectedInput.attributes).map(a => a.name + '="' + a.value + '"').join(', '));
        console.log('Provider ID detected:', providerId);
        return providerId;
    }

    // Función para obtener el texto del método de pago seleccionado
    function getSelectedPaymentText() {
        var selectedInput = document.querySelector('input[name="o_payment_radio"]:checked');
        if (!selectedInput) return null;
        // Buscar el texto asociado (puede estar en un label o en un elemento hermano)
        var label = selectedInput.closest('label') || selectedInput.parentElement.querySelector('label, span');
        if (label) return label.innerText.trim();
        // Si no hay label, buscar un span con la clase .payment_method_name
        var textSpan = selectedInput.parentElement.querySelector('.payment_method_name');
        if (textSpan) return textSpan.innerText.trim();
        return null;
    }

    // Función que muestra/oculta la sección según la selección
    function toggleProofSection() {
        var selectedValue = getSelectedPaymentProviderId();
        var selectedText = getSelectedPaymentText();
        var proofSection = document.getElementById('payment_proof_section');
        var transferProviderId = document.getElementById('transfer_provider_id')?.value;

        console.log('Selected ID:', selectedValue, 'Selected text:', selectedText);
        console.log('Transfer provider ID:', transferProviderId);

        if (proofSection && transferProviderId) {
            // Comparar por ID si se obtuvo, si no, comparar por texto
            var shouldShow = false;
            if (selectedValue && String(selectedValue) === String(transferProviderId)) {
                shouldShow = true;
                console.log('Match by ID');
            } else if (selectedText && selectedText.toLowerCase().includes('wire transfer')) {
                shouldShow = true;
                console.log('Match by text: "Wire Transfer"');
            }

            proofSection.style.display = shouldShow ? 'block' : 'none';
            console.log('Section display set to:', proofSection.style.display);
        } else {
            console.warn('Missing elements: proofSection=', proofSection, 'transferProviderId=', transferProviderId);
        }
    }

    // Subida del archivo
    function uploadFile(file) {
        var formData = new FormData();
        formData.append('payment_proof_file', file);
        fetch('/shop/upload_payment_proof', {
            method: 'POST',
            body: formData,
            credentials: 'same-origin'
        })
        .then(response => {
            if (response.ok) {
                alert('Comprobante adjuntado correctamente.');
            } else {
                alert('Error al adjuntar el comprobante. Intente nuevamente.');
            }
        })
        .catch(() => alert('Error de red. Intente más tarde.'));
    }

    // Inicialización
    document.addEventListener('DOMContentLoaded', function() {
        console.log('DOM ready, initializing');
        toggleProofSection();

        // Evento cambio en radios
        var radioButtons = document.querySelectorAll('input[name="o_payment_radio"]');
        console.log('Found', radioButtons.length, 'radio buttons');
        radioButtons.forEach(function(radio) {
            radio.addEventListener('change', toggleProofSection);
        });

        // Evento cambio en archivo
        var fileInput = document.getElementById('payment_proof_file');
        if (fileInput) {
            fileInput.addEventListener('change', function(e) {
                if (e.target.files.length) {
                    uploadFile(e.target.files[0]);
                }
            });
        }

        // Botón de prueba
        var testButton = document.getElementById('test_show_voucher');
        if (testButton) {
            testButton.addEventListener('click', function() {
                var section = document.getElementById('payment_proof_section');
                if (section) {
                    section.style.display = 'block';
                    console.log('Test button: forced display block');
                }
            });
        }
    });
})();
